import { createBrowserRouter, RouteObject } from 'react-router-dom'
import Layout from './components/Layout'
import HomePage from './pages/HomePage'
import NotFoundPage from './pages/NotFoundPage'

// =============================================================================
// CODERBLOCK NAVIGATION TRACKING
// Auto-initialize navigation tracking for Coderblock editor integration.
// =============================================================================
if (typeof window !== 'undefined' && window.parent !== window) {
  const sendNavigationUpdate = () => {
    const path = window.location.pathname + window.location.search + window.location.hash
    window.parent.postMessage({
      type: 'coderblock-navigation',
      mode: 'live',
      path: path || '/'
    }, '*')
  }

  const originalPushState = history.pushState
  const originalReplaceState = history.replaceState

  history.pushState = function(...args: Parameters<typeof history.pushState>) {
    originalPushState.apply(history, args)
    setTimeout(sendNavigationUpdate, 0)
  }

  history.replaceState = function(...args: Parameters<typeof history.replaceState>) {
    originalReplaceState.apply(history, args)
    setTimeout(sendNavigationUpdate, 0)
  }

  window.addEventListener('popstate', sendNavigationUpdate)
  sendNavigationUpdate()
}

// =============================================================================
// 🚨 ROUTE CONFIGURATION - IMPORTANT!
// =============================================================================
// 
// ⚠️ EVERY <Link to="/path"> MUST have a matching route entry here!
// 
// ADDING NEW PAGES:
// 1. Create the page file: src/pages/YourPage.tsx
// 2. Import it at the top of this file
// 3. Add route entry in the children array below
// 
// EXAMPLES:
// 
// Static route:
//   { path: 'about', element: <AboutPage /> }
//   Link: <Link to="/about">About</Link>
// 
// Dynamic route (with parameter):
//   { path: 'products/:id', element: <ProductDetailPage /> }
//   Link: <Link to={`/products/${product.id}`}>View Product</Link>
// 
// Nested route:
//   { path: 'dashboard', element: <DashboardLayout />, children: [...] }
// 
// =============================================================================

const routes: RouteObject[] = [
  {
    path: '/',
    element: <Layout />,
    children: [
      // Home page (index route)
      {
        index: true,
        element: <HomePage />
      },

      // ═══════════════════════════════════════════════════════════════════
      // ADD YOUR ROUTES HERE - Examples:
      // ═══════════════════════════════════════════════════════════════════
      // 
      // { path: 'about', element: <AboutPage /> },
      // { path: 'contact', element: <ContactPage /> },
      // 
      // For e-commerce/catalog:
      // { path: 'products', element: <ProductsPage /> },
      // { path: 'products/:id', element: <ProductDetailPage /> },
      // { path: 'categories', element: <CategoriesPage /> },
      // { path: 'categories/:slug', element: <CategoryPage /> },
      // { path: 'cart', element: <CartPage /> },
      // { path: 'checkout', element: <CheckoutPage /> },
      // 
      // For user accounts:
      // { path: 'login', element: <LoginPage /> },
      // { path: 'register', element: <RegisterPage /> },
      // { path: 'profile', element: <ProfilePage /> },
      // { path: 'orders', element: <OrdersPage /> },
      // { path: 'orders/:id', element: <OrderDetailPage /> },
      // 
      // Admin routes:
      // { path: 'admin', element: <AdminLayout />, children: [...] },
      // ═══════════════════════════════════════════════════════════════════

      // 🔴 CATCH-ALL: 404 for unknown routes (KEEP THIS LAST!)
      // This ensures 404 pages still show the navigation header
      {
        path: '*',
        element: <NotFoundPage />
      }
    ]
  }
]

export const router = createBrowserRouter(routes)

export default router

