/**
 * API Client Configuration
 *
 * 🔌 CRITICAL: This is the CORRECT way to handle API URLs in Coderblock apps!
 *
 * ⚠️ NEVER hardcode localhost:8000 in your code!
 * ⚠️ ALWAYS use this API_BASE_URL constant for all API calls!
 *
 * How it works:
 * - Development: Uses localhost:8000/api (from fallback)
 * - Production: Uses deployed backend URL (from .env.production set by deployment)
 *
 * The VITE_API_URL is automatically set when backend is deployed:
 * - Deployment creates .env.production with: VITE_API_URL=https://cb-xxx.fly.dev/api
 * - Vite reads this during build and injects it into import.meta.env
 *
 * Example usage in your components:
 *   import { apiClient } from '@/services/api';
 *   const items = await apiClient.get('/items');  ✅ CORRECT
 *
 * DO NOT DO THIS:
 *   fetch('http://localhost:8000/api/items')  ❌ WRONG - breaks in production!
 */

// 🔌 API base URL - automatically configured for dev/prod
// Uses VITE_API_URL from .env.production when deployed, falls back to localhost for dev
const API_BASE_URL = import.meta.env.VITE_API_URL || 'http://localhost:8000/api';

/**
 * Normalize endpoint to prevent double /api prefix
 * Example: normalizeEndpoint('/api/items') => '/items'
 * Example: normalizeEndpoint('/items') => '/items'
 */
function normalizeEndpoint(endpoint: string): string {
  // Remove leading /api if present (API_BASE_URL already includes it)
  return endpoint.startsWith('/api/') ? endpoint.substring(4) : endpoint;
}

/**
 * Build full URL from endpoint
 * Handles both absolute URLs and relative endpoints
 */
function buildUrl(endpoint: string): string {
  // If endpoint is absolute URL (http/https), use it as-is
  if (endpoint.startsWith('http://') || endpoint.startsWith('https://')) {
    return endpoint;
  }

  // Normalize and combine with base URL
  const normalized = normalizeEndpoint(endpoint);
  return `${API_BASE_URL}${normalized}`;
}

/**
 * Example API client using fetch
 *
 * Usage:
 *   apiClient.get('/items')           ✅ Correct
 *   apiClient.get('/api/items')       ✅ Also works (auto-normalized)
 *   apiClient.post('/items', data)    ✅ Correct
 */
export const apiClient = {
  async get<T>(endpoint: string): Promise<T> {
    const url = buildUrl(endpoint);
    const response = await fetch(url);
    if (!response.ok) {
      throw new Error(`API Error: ${response.statusText}`);
    }
    return response.json();
  },

  async post<T>(endpoint: string, data: any): Promise<T> {
    const url = buildUrl(endpoint);
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(data),
    });
    if (!response.ok) {
      throw new Error(`API Error: ${response.statusText}`);
    }
    return response.json();
  },

  async put<T>(endpoint: string, data: any): Promise<T> {
    const url = buildUrl(endpoint);
    const response = await fetch(url, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify(data),
    });
    if (!response.ok) {
      throw new Error(`API Error: ${response.statusText}`);
    }
    return response.json();
  },

  async delete<T>(endpoint: string): Promise<T> {
    const url = buildUrl(endpoint);
    const response = await fetch(url, {
      method: 'DELETE',
    });
    if (!response.ok) {
      throw new Error(`API Error: ${response.statusText}`);
    }
    return response.json();
  },
};

// Export base URL for direct use if needed
export { API_BASE_URL };
